/**
 * Resolves the true leads.id for a JWT-authenticated client user.
 *
 * The JWT stores the lead id at sign-in time. If the lead row was later
 * remapped (e.g. merged, recreated by Stripe webhook, or id sequence reset)
 * the JWT id may no longer exist in the leads table, causing FK violations
 * on individual_owner_id and 404s throughout.
 *
 * Strategy:
 *   1. If id exists in leads → return it (fast path, 99% of calls).
 *   2. Otherwise look up by email → return that id and async-patch the JWT
 *      claim is NOT patchable, but we stamp client_last_login so the user
 *      gets a fresh token on next login.
 *
 * @param {number} jwtId   - req.user.id from JWT
 * @param {string} jwtEmail - req.user.email from JWT
 * @returns {number|null} the real lead id, or null if not found
 */
async function resolveLeadId(jwtId, jwtEmail) {
    // Fast path — id still valid
    const byId = await pool.query('SELECT id FROM leads WHERE id=$1', [jwtId]);
    if (byId.rows.length) return jwtId;

    // Fallback — look up by email (portal accounts have client_password set)
    if (!jwtEmail) return null;
    const byEmail = await pool.query(
        `SELECT id FROM leads WHERE LOWER(email)=LOWER($1) AND client_password IS NOT NULL LIMIT 1`,
        [jwtEmail]
    );
    if (!byEmail.rows.length) return null;

    const realId = byEmail.rows[0].id;
    console.warn(`[resolveLeadId] JWT id=${jwtId} not found; resolved to id=${realId} via email ${jwtEmail}`);
    return realId;
}

/**
 * Resolves the active plan limits object for a logged-in client user.
 * Looks up their subscription via portal ID first (covers workspace members),
 * then falls back to individual subscription by email.
 * Returns { planKey, ...limits }
 */
async function getClientPlanLimits(userId) {
    try {
        const resolvedId = await resolveLeadId(userId, null).catch(() => userId) || userId;
        // 1. Try via portal ID (workspace users + individual users who have one)
        const leadRow = await pool.query(
            'SELECT client_portal_id, email FROM leads WHERE id=$1', [resolvedId]
        );
        const { client_portal_id: portalId, email } = leadRow.rows[0] || {};

        if (portalId) {
            const sub = await pool.query(
                `SELECT package_key FROM crm_subscriptions
                 WHERE client_portal_id=$1 AND status='active'
                 ORDER BY created_at DESC LIMIT 1`,
                [portalId]
            );
            const key = sub.rows[0]?.package_key;
            if (key && PLAN_LIMITS[key]) return { planKey: key, ...PLAN_LIMITS[key] };
        }

        // 2. Fallback: individual subscription by email
        if (email) {
            const sub = await pool.query(
                `SELECT package_key FROM crm_subscriptions
                 WHERE LOWER(lead_email)=LOWER($1) AND status='active'
                 ORDER BY created_at DESC LIMIT 1`,
                [email]
            );
            const key = sub.rows[0]?.package_key;
            if (key && PLAN_LIMITS[key]) return { planKey: key, ...PLAN_LIMITS[key] };
        }
    } catch(e) {
        console.error('[PLAN_LIMITS] lookup error:', e.message);
    }
    return { planKey: '_default', ...PLAN_LIMITS['_default'] };
}

/**
 * Returns the combined count of leads + contacts + customers for a portal.
 * Used to enforce the per-plan record cap.
 */
async function getClientRecordCount(portalId) {
    try {
        const [leads, contacts, customers] = await Promise.all([
            pool.query('SELECT COUNT(*) AS n FROM leads WHERE client_portal_id=$1', [portalId]),
            pool.query('SELECT COUNT(*) AS n FROM client_contacts WHERE client_id IN (SELECT id FROM leads WHERE client_portal_id=$1)', [portalId])
                .catch(() => ({ rows: [{ n: 0 }] })),
            pool.query('SELECT COUNT(*) AS n FROM customers WHERE client_portal_id=$1', [portalId])
                .catch(() => ({ rows: [{ n: 0 }] })),
        ]);
        return (
            parseInt(leads.rows[0]?.n || 0) +
            parseInt(contacts.rows[0]?.n || 0) +
            parseInt(customers.rows[0]?.n || 0)
        );
    } catch { return 0; }
}

/**
 * Returns how many follow-up emails this user has sent today.
 * Used to enforce the per-plan daily follow-up cap.
 */
async function getFollowUpsTodayCount(userEmail) {
    // Combined daily cap: counts ALL outbound sends — follow-up emails, marketing emails, AND SMS
    // Analytics separates them, but the daily limit applies to the total
    try {
        const emailCount = await pool.query(
            `SELECT COUNT(*) AS n FROM client_email_log
             WHERE LOWER(assigned_to_user_email)=LOWER($1)
               AND email_type IN ('follow-up','manual','email','marketing')
               AND created_at >= CURRENT_DATE`,
            [userEmail]
        );
        // SMS sends are logged to message_log (outbound channel='sms')
        // We identify user's SMS by portal — get portalId from email
        const smsCount = await pool.query(
            `SELECT COUNT(*) AS n FROM message_log ml
             JOIN leads l ON ml.lead_id = l.id
             WHERE ml.direction='outbound' AND ml.channel='sms'
               AND ml.sent_at >= CURRENT_DATE
               AND (
                 LOWER(l.email)=LOWER($1)
                 OR EXISTS (
                   SELECT 1 FROM leads lu
                   WHERE LOWER(lu.email)=LOWER($1)
                     AND lu.client_portal_id IS NOT NULL
                     AND ml.client_portal_id = lu.client_portal_id
                   LIMIT 1
                 )
               )`,
            [userEmail]
        ).catch(() => ({ rows: [{ n: 0 }] }));
        return (parseInt(emailCount.rows[0]?.n || 0)) + (parseInt(smsCount.rows[0]?.n || 0));
    } catch { return 0; }
}

function currentBillingMonth() {
    const d = new Date();
    return new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), 1)).toISOString().split('T')[0];
}

