const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-this';

// ========================================
// SHARED: Tracked email sender
// Logs to email_log, injects open-tracking pixel, then sends.
// Use this for ALL follow-up / outreach sends so the analytics report is accurate.
// ========================================
// ========================================
// EMAIL SENDING HELPERS
// ========================================

// Send email via Brevo
async function sendViaBrevo(brevoApiKey, senderEmail, senderName, to, subject, html, attachments = [], verifiedDomain = null) {
    // Use Brevo REST API directly — no SDK dependency, no constructor issues.
    const https = require('https');

    // ── Sender verification workaround ───────────────────────────────────
    // Brevo rejects unverified sender addresses (e.g. client Gmail accounts).
    // Solution: always send FROM the verified platform address, set replyTo to
    // the client's address so replies go directly to them, and include their
    // identity in the display name so recipients know who it's from.
    //
    // Recipients see:  "Taylor Crownover via Diamondback CRM <contact@diamondbackcoding.com>"
    // Replies go to:   taylor.crownover2024@gmail.com
    // ── Sender verification logic ─────────────────────────────────────────
    // If the sender's email domain is verified in Brevo, send directly from
    // their address — fully branded, no "via" label, best deliverability.
    // If not verified, fall back to platform address with reply-to so it
    // still works without any setup required from the client.
    const senderDomain = senderEmail ? senderEmail.split('@')[1]?.toLowerCase() : null;
    const domainIsVerified = verifiedDomain && senderDomain &&
        (senderDomain === verifiedDomain.toLowerCase() || senderDomain.endsWith('.' + verifiedDomain.toLowerCase()));

    let actualSenderEmail, displayName, replyTo;
    if (domainIsVerified) {
        // Verified domain — send directly from client address, no "via" branding
        actualSenderEmail = senderEmail;
        displayName = senderName || senderEmail.split('@')[0];
        replyTo = null;
        console.log(`[BREVO] Verified domain — sending directly from: ${senderEmail}`);
    } else {
        // Unverified — use platform address, show client name, set reply-to
        actualSenderEmail = PLATFORM_SENDER_EMAIL;
        displayName = (senderEmail && senderEmail.toLowerCase() !== PLATFORM_SENDER_EMAIL.toLowerCase())
            ? `${senderName || senderEmail.split('@')[0]} via Diamondback CRM`
            : (senderName || 'Diamondback CRM');
        replyTo = (senderEmail && senderEmail.toLowerCase() !== PLATFORM_SENDER_EMAIL.toLowerCase())
            ? { email: senderEmail, name: senderName || senderEmail.split('@')[0] }
            : null;
    }

    const payload = {
        sender: { email: actualSenderEmail, name: displayName },
        to: [{ email: to }],
        subject,
        htmlContent: html,
        ...(replyTo ? { replyTo } : {})
    };

    if (attachments && attachments.length > 0) {
        payload.attachment = attachments.map(att => ({
            name: att.filename,
            content: Buffer.isBuffer(att.content)
                ? att.content.toString('base64')
                : att.content
        }));
    }

    const body = JSON.stringify(payload);
    console.log('[BREVO] Sending | to:', to, '| from:', actualSenderEmail, '| display:', displayName, '| reply-to:', replyTo?.email || 'none', '| key prefix:', brevoApiKey ? brevoApiKey.substring(0,8)+'...' : 'MISSING');

    return new Promise((resolve, reject) => {
        const options = {
            hostname: 'api.brevo.com',
            path: '/v3/smtp/email',
            method: 'POST',
            headers: {
                'accept': 'application/json',
                'api-key': brevoApiKey,
                'content-type': 'application/json',
                'content-length': Buffer.byteLength(body)
            }
        };

        const req = https.request(options, (res) => {
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', () => {
                try {
                    const parsed = JSON.parse(data);
                    if (res.statusCode >= 200 && res.statusCode < 300) {
                        const messageId = parsed.messageId || null;
                        console.log('[BREVO]  Email accepted. Message ID:', messageId);
                        resolve({ messageId });
                    } else {
                        const errMsg = parsed.message || parsed.error || `HTTP ${res.statusCode}`;
                        console.error('[BREVO]  API error:', errMsg);
                        reject(new Error(`Brevo send failed: ${errMsg}`));
                    }
                } catch (e) {
                    reject(new Error(`Brevo response parse error: ${e.message}`));
                }
            });
        });

        req.on('error', (e) => {
            console.error('[BREVO]  Request error:', e.message);
            reject(new Error(`Brevo request failed: ${e.message}`));
        });

        req.write(body);
        req.end();
    });
}

// Validate email domain has mail servers BEFORE sending
async function validateEmailDomain(email) {
    try {
        // Basic format check only - DNS checks can cause false failures
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        if (!emailRegex.test(email)) {
            return { valid: false, reason: 'Invalid email format' };
        }

        // Extract domain
        const domain = email.split('@')[1].toLowerCase();
        
        // Common typo detection only - no DNS lookups
        const commonTypos = {
            'gmial.com': 'gmail.com',
            'gmai.com': 'gmail.com',
            'yahooo.com': 'yahoo.com',
            'yaho.com': 'yahoo.com',
            'hotmial.com': 'hotmail.com',
            'outlok.com': 'outlook.com',
            'outloo.com': 'outlook.com'
        };
        
        if (commonTypos[domain]) {
            return { 
                valid: false, 
                reason: `Possible typo detected. Did you mean ${commonTypos[domain]}?`,
                suggestion: email.replace(domain, commonTypos[domain])
            };
        }
        
        // Don't do DNS validation - it causes too many false failures
        // Let the mail server handle validation instead
        console.log(`[EMAIL-VALIDATION]  Email format valid: ${email}`);
        return { valid: true };
        
    } catch (error) {
        console.error('[EMAIL-VALIDATION] Error validating email:', error);
        // On unexpected errors, assume valid to avoid blocking legitimate emails
        return { valid: true, warning: `Validation error: ${error.message}` };
    }
}

// ========================================
// sendSystemEmail — sends via the admin portal's Brevo account.
// Used for user-management emails (welcome, password reset) so they
// are NEVER logged to email_log and NEVER appear in email analytics.
// ========================================
async function sendSystemEmail({ to, subject, html }) {
    // Always use the platform-level (admin portal) Brevo credentials
    const emailSettings = await getEmailSettings();

    // Hard-coded platform sender — always Diamondback, never the admin's personal email
    const PLATFORM_SENDER_EMAIL = 'contact@diamondbackcoding.com';
    const PLATFORM_SENDER_NAME  = 'Diamondback Coding';

    try {
        if (emailSettings.useBrevo && emailSettings.brevoApiKey) {
            console.log(`[SYSTEM EMAIL] Sending via Brevo | TO: ${to} | FROM: ${PLATFORM_SENDER_EMAIL} | Subject: ${subject}`);
            await sendViaBrevo(
                emailSettings.brevoApiKey,
                PLATFORM_SENDER_EMAIL,
                PLATFORM_SENDER_NAME,
                to,       // <-- always the new user, never the admin
                subject,
                html,
                []
            );
            console.log(`[SYSTEM EMAIL]  Brevo accepted delivery to: ${to}`);
        } else {
            // Fallback to nodemailer
            console.log(`[SYSTEM EMAIL] Brevo not configured — sending via Nodemailer | TO: ${to} | Subject: ${subject}`);
            await transporter.sendMail({
                from: `"${PLATFORM_SENDER_NAME}" <${process.env.EMAIL_USER || PLATFORM_SENDER_EMAIL}>`,
                to,
                subject,
                html
            });
            console.log(`[SYSTEM EMAIL]  Nodemailer delivered to: ${to}`);
        }
    } catch (err) {
        console.error(`[SYSTEM EMAIL]  Failed to send to ${to}:`, err.message);
        throw err;
    }
}

// Get current email settings
async function getEmailSettings() {
    try {
        // Prefer admin user who has Brevo enabled and configured
        const result = await pool.query(`
            SELECT settings FROM admin_users 
            WHERE settings IS NOT NULL 
              AND settings->>'useBrevo' = 'true' 
              AND settings->>'brevoApiKey' IS NOT NULL 
              AND settings->>'brevoApiKey' != ''
            ORDER BY updated_at DESC NULLS LAST 
            LIMIT 1
        `);
        if (result.rows.length > 0 && result.rows[0].settings) {
            return result.rows[0].settings;
        }
        // Fallback: any admin with settings
        const fallback = await pool.query('SELECT settings FROM admin_users WHERE settings IS NOT NULL LIMIT 1');
        if (fallback.rows.length > 0 && fallback.rows[0].settings) {
            return fallback.rows[0].settings;
        }
        return { useBrevo: false };
    } catch (error) {
        console.error('[EMAIL SETTINGS] Error fetching settings:', error);
        return { useBrevo: false };
    }
}

async function sendTrackedEmail({ leadId, to, subject, html, isMarketing = false, emailType = 'follow-up' }) {
    // 1. Create email_log row with 'pending' status BEFORE sending so we have the ID
    let emailLogId = null;
    try {
        const logRow = await pool.query(
            `INSERT INTO email_log (lead_id, subject, status, email_type) VALUES ($1, $2, 'pending', $3) RETURNING id`,
            [leadId || null, subject, emailType]
        );
        emailLogId = logRow.rows[0]?.id;
        console.log(`[EMAIL] Created email_log entry ${emailLogId} for ${to} - Status: pending - Type: ${emailType}`);
    } catch (e) {
        console.warn('[TRACKED-EMAIL] Could not insert email_log row:', e.message);
    }

    // 2. Determine if this email should be tracked (open pixel + link tracking)
    // Confirmation emails should NOT be tracked — they're transactional, not engagement-driven
    const confirmationTypes = [
        'appointment_confirmation', 
        'appointment_cancelled', 
        'appointment_rescheduled', 
        'subscription_welcome',
        'subscription_receipt',
        'subscription_cancelled',
        'subscription_change',
        'subscription_payment_failed',
        'subscription_duplicate'
    ];
    const shouldTrack = !confirmationTypes.includes(emailType);
    
    if (!shouldTrack) {
        console.log(`[EMAIL] Type '${emailType}' is a confirmation — skipping tracking pixel and link wrapping`);
    }

    // 3. VALIDATE EMAIL DOMAIN BEFORE SENDING - Catch typos early!
    console.log(`[EMAIL] Validating email address: ${to}`);
    const validation = await validateEmailDomain(to);
    
    if (!validation.valid) {
        console.error(`\n========================================`);
        console.error(`[EMAIL]  EMAIL VALIDATION FAILED `);
        console.error(`[EMAIL] To: ${to}`);
        console.error(`[EMAIL] Reason: ${validation.reason}`);
        if (validation.suggestion) {
            console.error(`[EMAIL] Suggestion: ${validation.suggestion}`);
        }
        console.error(`========================================\n`);
        
        // Mark as failed BEFORE attempting to send
        if (emailLogId) {
            await pool.query(
                `UPDATE email_log 
                 SET status = 'failed', 
                     error_message = $2,
                     sent_at = CURRENT_TIMESTAMP 
                 WHERE id = $1`,
                [emailLogId, `Email validation failed: ${validation.reason}`]
            );
            console.log(`[EMAIL]  Email_log ${emailLogId} marked as FAILED (validation failed)`);
        }
        
        console.log(`[FOLLOW-UP]  Lead ${leadId} NOT advanced - email validation failed\n`);
        throw new Error(`Email validation failed: ${validation.reason}`);
    }
    
    console.log(`[EMAIL]  Email validation passed for ${to}`);
    if (validation.warning) {
        console.warn(`[EMAIL] ️  Warning: ${validation.warning}`);
    }

    // 4. Inject 1×1 open-tracking pixel (skip for confirmation emails)
    if (emailLogId && shouldTrack) {
        const pixel = `<img src="${BASE_URL}/api/track/open/${emailLogId}" width="1" height="1" style="display:none;border:0;" alt="" />`;
        html = html.replace(/<\/body>/i, `${pixel}</body>`);
        if (!html.includes(pixel)) html += pixel; // fallback if no </body>
        
        console.log(`[EMAIL] Tracking pixel inserted: ${BASE_URL}/api/track/open/${emailLogId}`);
        console.log(`[EMAIL] When this email is opened, the pixel will load and trigger the tracking endpoint`);
    }

    // 5. Wrap ALL diamondbackcoding.com links with tracking (makes leads hot when clicked, skip for confirmation emails)
    if (leadId && emailLogId && shouldTrack) {
        // Replace all diamondbackcoding.com links with tracked versions
        const websiteUrlPattern = /(https?:\/\/(?:www\.)?diamondbackcoding\.com[^"'\s]*)/gi;
        html = html.replace(websiteUrlPattern, (match) => {
            // Don't double-wrap or wrap tracking URLs
            if (match.includes('/api/track/click/')) return match;
            if (match.includes('/api/track/open/')) return match;
            return `${BASE_URL}/api/track/click/${leadId}?email_id=${emailLogId}&url=${encodeURIComponent(match)}`;
        });
    }

    // 6. Get email settings to check if Brevo is enabled
    const emailSettings = await getEmailSettings();
    
    // 7. Send via Brevo or Nodemailer
    try {
        console.log(`[EMAIL] Attempting to send to: ${to} | Subject: ${subject} | Method: ${emailSettings.useBrevo ? 'Brevo' : 'Nodemailer'}`);
        
        if (emailSettings.useBrevo && emailSettings.brevoApiKey) {
            console.log('[EMAIL] Sending via Brevo...');
            const brevoResult = await sendViaBrevo(
                emailSettings.brevoApiKey,
                emailSettings.brevoSenderEmail || process.env.EMAIL_USER,
                emailSettings.brevoSenderName || 'Diamondback Coding',
                to,
                subject,
                html
            );
            console.log(`[EMAIL]  Email accepted by Brevo for ${to}`);
            // Store Brevo's message-id so the webhook can look up the exact row
            if (emailLogId && brevoResult?.messageId) {
                await pool.query(
                    `UPDATE email_log SET brevo_message_id = $2 WHERE id = $1`,
                    [emailLogId, brevoResult.messageId]
                );
                console.log(`[EMAIL] Stored brevo_message_id ${brevoResult.messageId} on email_log ${emailLogId}`);
            }
        } else {
            console.log('[EMAIL] Sending via Nodemailer...');
            const info = await transporter.sendMail({
                from: `"Diamondback Coding" <${process.env.EMAIL_USER}>`,
                to,
                subject,
                html
            });
            
            console.log(`[EMAIL] Nodemailer messageId: ${info.messageId}`);
            console.log(`[EMAIL] Nodemailer response: ${info.response}`);
            
            // Check if email was rejected by the mail server
            if (info.rejected && info.rejected.length > 0) {
                throw new Error(`Email rejected by mail server: ${info.rejected.join(', ')}`);
            }
            
            console.log(`[EMAIL]  Email accepted by mail server for ${to}`);
        }
        
        // 7. Mark as 'queued' for Brevo (awaiting bounce window) or 'sent' for Nodemailer
        if (emailLogId) {
            const newStatus = emailSettings.useBrevo ? 'queued' : 'sent';
            await pool.query(
                `UPDATE email_log 
                 SET status = $2, 
                     sent_at = CURRENT_TIMESTAMP 
                 WHERE id = $1`,
                [emailLogId, newStatus]
            );
            console.log(`[EMAIL]  Email_log ${emailLogId} marked as ${newStatus.toUpperCase()}`);
        }
        
        // 8. Update follow-up tracking since email was successfully sent
        if (leadId && !isMarketing) {
            await pool.query(
                `UPDATE leads 
                 SET last_contact_date = CURRENT_DATE,
                     follow_up_count = COALESCE(follow_up_count, 0) + 1,
                     updated_at = CURRENT_TIMESTAMP,
                     status = CASE 
                         WHEN status = 'new' THEN 'contacted'
                         ELSE status
                     END
                 WHERE id = $1`,
                [leadId]
            );
            console.log(`[FOLLOW-UP]  Lead ${leadId} advanced - email sent successfully`);
        }
        
    } catch (error) {
        console.error(`\n========================================`);
        console.error(`[EMAIL]  SEND FAILED `);
        console.error(`[EMAIL] To: ${to}`);
        console.error(`[EMAIL] Subject: ${subject}`);
        console.error(`[EMAIL] Error: ${error.message}`);
        console.error(`========================================\n`);
        
        // Mark as failed - DO NOT update follow_up_count or last_contact_date
        if (emailLogId) {
            await pool.query(
                `UPDATE email_log SET status = 'failed', sent_at = CURRENT_TIMESTAMP, error_message = $2 WHERE id = $1`,
                [emailLogId, error.message]
            );
            console.log(`[EMAIL]  Email_log ${emailLogId} marked as FAILED`);
        }
        
        console.log(`[FOLLOW-UP]  Lead ${leadId} NOT advanced - email failed to send\n`);
        
        throw error;
    }

    return emailLogId;
}

// ========================================
// UNIFIED EMAIL SEND WITH TRACKING
// All emails now go through tracking for accurate analytics
// ========================================
async function sendDirectEmail({ to, subject, html, attachments = [], leadId = null, emailType = 'system' }) {
    // Create email_log entry for ALL emails (not just follow-ups)
    let emailLogId = null;
    try {
        const logRow = await pool.query(
            `INSERT INTO email_log (lead_id, subject, status, email_type) VALUES ($1, $2, 'pending', $3) RETURNING id`,
            [leadId || null, subject, emailType]
        );
        emailLogId = logRow.rows[0]?.id;
        console.log(`[EMAIL] Created email_log entry ${emailLogId} for ${to} - Type: ${emailType}`);
    } catch (e) {
        console.warn('[EMAIL] Could not insert email_log row:', e.message);
    }

    // NO CUSTOM TRACKING PIXEL - Brevo handles all open tracking via webhooks
    console.log(`[EMAIL] Relying on Brevo webhook for open tracking (no custom pixel)`);

    // NO CUSTOM LINK TRACKING - Brevo handles all click tracking via webhooks
    console.log(`[EMAIL] Relying on Brevo webhook for click tracking (no custom link wrapping)`);

    const emailSettings = await getEmailSettings();

    try {
        console.log(`[EMAIL] Sending to: ${to} | Subject: ${subject} | Type: ${emailType} | Method: ${emailSettings.useBrevo ? 'Brevo' : 'Nodemailer'}`);

        if (emailSettings.useBrevo && emailSettings.brevoApiKey) {
            console.log('[EMAIL] Sending via Brevo...');
            const brevoResult = await sendViaBrevo(
                emailSettings.brevoApiKey,
                emailSettings.brevoSenderEmail || process.env.EMAIL_USER,
                emailSettings.brevoSenderName || 'Diamondback Coding',
                to,
                subject,
                html,
                attachments
            );
            console.log(`[EMAIL]  Email accepted by Brevo for ${to}`);
            
            // Store Brevo message-id for webhook tracking
            if (emailLogId && brevoResult?.messageId) {
                await pool.query(
                    `UPDATE email_log SET brevo_message_id = $2 WHERE id = $1`,
                    [emailLogId, brevoResult.messageId]
                );
                console.log(`[EMAIL] Stored brevo_message_id ${brevoResult.messageId} on email_log ${emailLogId}`);
            }
        } else {
            // Use Nodemailer for attachments or when Brevo is not configured
            console.log('[EMAIL] Sending via Nodemailer...');
            const info = await transporter.sendMail({
                from: `"Diamondback Coding" <${process.env.EMAIL_USER}>`,
                to,
                subject,
                html,
                attachments
            });
            
            console.log(`[EMAIL] Nodemailer messageId: ${info.messageId}`);
            console.log(`[EMAIL] Nodemailer response: ${info.response}`);
            
            if (info.rejected && info.rejected.length > 0) {
                throw new Error(`Email rejected by mail server: ${info.rejected.join(', ')}`);
            }
            
            console.log(`[EMAIL]  Email accepted by mail server for ${to}`);
        }
        
        // Mark as 'queued' for Brevo or 'sent' for Nodemailer
        if (emailLogId) {
            const newStatus = emailSettings.useBrevo ? 'queued' : 'sent';
            await pool.query(
                `UPDATE email_log 
                 SET status = $2, 
                     sent_at = CURRENT_TIMESTAMP 
                 WHERE id = $1`,
                [emailLogId, newStatus]
            );
            console.log(`[EMAIL]  Email_log ${emailLogId} marked as ${newStatus.toUpperCase()}`);
        }
        
    } catch (error) {
        console.error(`\n========================================`);
        console.error(`[EMAIL]  SEND FAILED `);
        console.error(`[EMAIL] To: ${to}`);
        console.error(`[EMAIL] Subject: ${subject}`);
        console.error(`[EMAIL] Type: ${emailType}`);
        console.error(`[EMAIL] Error: ${error.message}`);
        console.error(`========================================\n`);
        
        // Mark as failed
        if (emailLogId) {
            await pool.query(
                `UPDATE email_log SET status = 'failed', sent_at = CURRENT_TIMESTAMP, error_message = $2 WHERE id = $1`,
                [emailLogId, error.message]
            );
            console.log(`[EMAIL]  Email_log ${emailLogId} marked as FAILED`);
        }
        
        throw error;
    }

    return emailLogId;
}

