// POST /api/client/leads — Create a lead
// ========================================
app.post('/api/client/leads', authenticateClient, async (req, res) => {
    try {
        // Resolve the true lead id — the JWT id may be stale if the leads row was
        // remapped after the token was issued (FK violation guard).
        const userId = await resolveLeadId(req.user.id, req.user.email);
        if (!userId) return res.status(400).json({ success: false, message: 'Account not found. Please log out and log back in.' });

        const { name, email, phone, company, status, notes, assignToSelf } = req.body;

        if (!name) return res.status(400).json({ success: false, message: 'Name is required' });

        // Resolve portal — individual users have no portal ID
        const clientPortalId = await getClientPortalId(userId);
        const isIndividualLead = !clientPortalId;

        // ── Record cap ──
        const planData = await getClientPlanLimits(userId);
        if (planData.maxRecords !== null) {
            let total;
            if (isIndividualLead) {
                const r = await pool.query(
                    `SELECT COUNT(*) FROM leads WHERE individual_owner_id=$1 AND client_password IS NULL AND (source IS NULL OR source NOT IN ('company-user','subscription-direct'))`,
                    [userId]
                );
                total = parseInt(r.rows[0].count);
            } else {
                total = await getClientRecordCount(clientPortalId);
            }
            if (total >= planData.maxRecords) {
                return res.status(403).json({
                    success: false,
                    limitReached: 'records',
                    limit: planData.maxRecords,
                    message: `Your ${planData.displayName} plan is limited to ${planData.maxRecords.toLocaleString()} total leads, contacts, and customers. Upgrade your plan to add more.`
                });
            }
        }

        // Get the creator's company_users record for auto-assign (workspace only)
        let assignedTo = null;
        if (!isIndividualLead && assignToSelf !== false) {
            const cuRecord = await getCompanyUserRecord(userId);
            if (cuRecord) assignedTo = cuRecord.id;
        }

        // Duplicate email check
        if (email) {
            const dupCheck = isIndividualLead
                ? await pool.query(`SELECT id FROM leads WHERE LOWER(email)=LOWER($1) AND individual_owner_id=$2 AND client_password IS NULL`, [email, userId])
                : await pool.query(`SELECT id FROM leads WHERE LOWER(email)=LOWER($1) AND client_portal_id=$2`, [email, clientPortalId]);
            if (dupCheck.rows.length > 0) {
                return res.status(409).json({ success: false, message: 'A lead with this email already exists' });
            }
        }

        const result = isIndividualLead
            ? await pool.query(`
                INSERT INTO leads (name, email, phone, company, status, notes, source,
                    lead_temperature, individual_owner_id, created_at, updated_at)
                VALUES ($1, $2, $3, $4, $5, $6, 'crm-portal', 'cold', $7, NOW(), NOW())
                RETURNING *
              `, [name, email || null, phone || null, company || null,
                  status || 'new', notes || null, userId])
            : await pool.query(`
                INSERT INTO leads (name, email, phone, company, status, notes, source,
                    lead_temperature, client_portal_id, crm_assigned_to, created_at, updated_at)
                VALUES ($1, $2, $3, $4, $5, $6, 'crm-portal', 'cold', $7, $8, NOW(), NOW())
                RETURNING *
              `, [name, email || null, phone || null, company || null,
                  status || 'new', notes || null, clientPortalId, assignedTo]);

        res.json({ success: true, lead: result.rows[0] });

    } catch (error) {
        console.error('[CLIENT LEADS] POST error:', error);
        res.status(500).json({ success: false, message: 'Server error' });
    }
});

// ========================================
// PATCH /api/client/leads/:id — Update a lead
// ========================================
app.patch('/api/client/leads/:id', authenticateClient, async (req, res) => {
    try {
        const userId = await resolveLeadId(req.user.id, req.user.email);
        if (!userId) return res.status(400).json({ success: false, message: 'Account not found. Please log out and log back in.' });
        const leadId = req.params.id;
        const { name, email, phone, company, status, notes, lead_temperature } = req.body;

        // Verify this lead belongs to user's portal or individual account — never their own account row
        const clientPortalId = await getClientPortalId(userId);

        const check = await pool.query(
            `SELECT id, lead_temperature as current_temp FROM leads
             WHERE id = $1
               AND client_password IS NULL
               AND (source IS NULL OR source NOT IN ('company-user','subscription-direct'))
               AND (client_portal_id = $2 OR individual_owner_id = $3)`,
            [leadId, clientPortalId, userId]
        );
        if (!check.rows.length) return res.status(404).json({ success: false, message: 'Lead not found' });

        const currentTemp = check.rows[0].current_temp;
        const becomingHot = lead_temperature === 'hot' && currentTemp !== 'hot';
        const becomingCold = lead_temperature === 'cold' && currentTemp === 'hot';

        // If manually marking hot: reset timeline so they show immediately in queue
        // If manually marking cold: pause any active hot chains, reset timeline to cold sequence
        let extraFields = '';
        if (becomingHot) {
            extraFields = `, became_hot_at = COALESCE(became_hot_at, NOW()), last_contact_date = NULL, follow_up_count = 0`;
            // Pause cold chain queue entries
            await pool.query(`UPDATE client_chain_queue SET is_active=FALSE WHERE lead_id=$1 AND is_active=TRUE`, [leadId]);
        } else if (becomingCold) {
            extraFields = `, became_hot_at = NULL, last_contact_date = NULL, follow_up_count = 0`;
            // Pause any hot chain queue entries too - user must re-enroll in a cold sequence
            await pool.query(`UPDATE client_chain_queue SET is_active=FALSE WHERE lead_id=$1 AND is_active=TRUE`, [leadId]);
        }

        const result = await pool.query(`
            UPDATE leads SET
                name = COALESCE($1, name),
                email = COALESCE($2, email),
                phone = COALESCE($3, phone),
                company = COALESCE($4, company),
                status = COALESCE($5, status),
                notes = COALESCE($6, notes),
                lead_temperature = COALESCE($7, lead_temperature)
                ${extraFields},
                updated_at = NOW()
            WHERE id = $8
            RETURNING *
        `, [name, email, phone, company, status, notes, lead_temperature || null, leadId]);

        res.json({ success: true, lead: result.rows[0] });

    } catch (error) {
        console.error('[CLIENT LEADS] PATCH error:', error);
        res.status(500).json({ success: false, message: 'Server error' });
    }
});

// ========================================
// DELETE /api/client/leads/:id — Delete a CRM lead (portal-scoped only)
// Only deletes the lead row itself. Never touches subscriptions, companies, or auth accounts.
// ========================================
app.delete('/api/client/leads/:id', authenticateClient, async (req, res) => {
    try {
        const userId = await resolveLeadId(req.user.id, req.user.email) || req.user.id;
        const leadId = req.params.id;
        const clientPortalId = await getClientPortalId(userId);

        const check = await pool.query(
            `SELECT id, email FROM leads
             WHERE id = $1
               AND client_password IS NULL
               AND (source IS NULL OR source NOT IN ('company-user', 'subscription-direct'))
               AND (client_portal_id = $2 OR individual_owner_id = $3)`,
            [leadId, clientPortalId, userId]
        );
        if (!check.rows.length) {
            return res.status(404).json({ success: false, message: 'Lead not found or cannot be deleted' });
        }

        await pool.query(`DELETE FROM client_chain_queue WHERE lead_id = $1`, [leadId]).catch(() => {});
        await pool.query(`DELETE FROM lead_notes WHERE lead_id = $1`, [leadId]).catch(() => {});
        await pool.query(`DELETE FROM client_email_log WHERE lead_id = $1`, [leadId]).catch(() => {});
        await pool.query(`DELETE FROM leads WHERE id = $1`, [leadId]);

        res.json({ success: true, message: 'Lead deleted' });

    } catch (error) {
        console.error('[CLIENT LEADS] DELETE error:', error);
        res.status(500).json({ success: false, message: 'Server error' });
    }
});

// ========================================
// POST /api/client/leads/:id/assign
// Assign a lead to any company team member
// Anyone on the team can assign to anyone
// ========================================
app.post('/api/client/leads/:id/assign', authenticateClient, async (req, res) => {
    try {
        const userId = req.user.id;
        const leadId = req.params.id;
        const { companyUserId } = req.body; // null to unassign

        // Verify lead is in user's portal
        const clientPortalId = await getClientPortalId(userId);
        if (!clientPortalId) return res.status(403).json({ success: false, message: 'Not part of a company' });

        const leadCheck = await pool.query(
            `SELECT id FROM leads WHERE id = $1 AND client_portal_id = $2`,
            [leadId, clientPortalId]
        );
        if (!leadCheck.rows.length) return res.status(404).json({ success: false, message: 'Lead not found' });

        // If assigning to someone, verify they're in the same company
        if (companyUserId) {
            const memberCheck = await pool.query(
                `SELECT id FROM company_users WHERE id = $1 AND client_portal_id = $2 AND status = 'active'`,
                [companyUserId, clientPortalId]
            );
            if (!memberCheck.rows.length) {
                return res.status(400).json({ success: false, message: 'User not found in your company' });
            }
        }

        await pool.query(
            `UPDATE leads SET crm_assigned_to = $1, updated_at = NOW() WHERE id = $2`,
            [companyUserId || null, leadId]
        );

        // Get the assignee name for response
        let assigneeName = null;
        if (companyUserId) {
            const cu = await pool.query(`SELECT user_name, user_label FROM company_users WHERE id = $1`, [companyUserId]);
            assigneeName = cu.rows[0]?.user_name || null;
        }

        res.json({ success: true, message: companyUserId ? `Assigned to ${assigneeName}` : 'Unassigned', assigneeName });

    } catch (error) {
        console.error('[CLIENT LEADS] ASSIGN error:', error);
        res.status(500).json({ success: false, message: 'Server error' });
    }
});

