// Client Login
app.post('/api/client/login', async (req, res) => {
    const { email, password } = req.body;
    if (!email || !password) return res.status(400).json({ success: false, message: 'Email and password required.' });

    try {
        // Look up by email — must have a client_password (CRM portal account)
        const result = await pool.query(
            `SELECT * FROM leads WHERE LOWER(email) = LOWER($1) AND client_password IS NOT NULL LIMIT 1`,
            [email]
        );

        if (!result.rows.length) {
            return res.status(401).json({
                success: false,
                message: 'Invalid email or password.'
            });
        }

        const lead = result.rows[0];

        // Verify password
        const passwordMatch = await bcrypt.compare(password, lead.client_password);
        if (!passwordMatch) {
            return res.status(401).json({ success: false, message: 'Invalid email or password.' });
        }

        // Resolve clientPortalId and admin status
        // Always check client_companies so admins whose lead row has stale/missing flags
        // still get isCompanyAdmin=true and the correct clientPortalId
        let clientPortalId = lead.client_portal_id || null;
        let isCompanyAdmin = lead.is_company_admin || false;

        const ccLookup = await pool.query(
            'SELECT client_portal_id FROM client_companies WHERE LOWER(admin_email) = LOWER($1) LIMIT 1',
            [lead.email]
        );
        if (ccLookup.rows[0]?.client_portal_id) {
            clientPortalId = ccLookup.rows[0].client_portal_id;
            isCompanyAdmin = true;
            // Stamp back so future requests are instant
            await pool.query(
                'UPDATE leads SET client_portal_id = $1, is_company_admin = TRUE WHERE id = $2',
                [clientPortalId, lead.id]
            ).catch(() => {});
        } else if (!clientPortalId) {
            // Not a company admin — try to find portal via company_users (workspace member)
            const cu = await pool.query(
                `SELECT client_portal_id FROM company_users WHERE LOWER(user_email)=LOWER($1) AND status='active' LIMIT 1`,
                [lead.email]
            );
            if (cu.rows[0]?.client_portal_id) {
                clientPortalId = cu.rows[0].client_portal_id;
                await pool.query(
                    'UPDATE leads SET client_portal_id=$1 WHERE id=$2',
                    [clientPortalId, lead.id]
                ).catch(() => {});
            } else {
                // Pure individual subscription — no company, no team.
                // They are the sole owner of their account so they get full admin rights.
                isCompanyAdmin = true;
            }
        }

        // Update last login timestamp
        await pool.query(
            'UPDATE leads SET client_last_login = CURRENT_TIMESTAMP WHERE id = $1',
            [lead.id]
        ).catch(() => {});

        // Generate JWT token
        const token = jwt.sign(
            { id: lead.id, email: lead.email, type: 'client' },
            JWT_SECRET,
            { expiresIn: '7d' }
        );

        // Resolve plan limits so the frontend can enforce UI restrictions immediately
        const planData = await getClientPlanLimits(lead.id);

        res.json({
            success: true,
            token,
            client: {
                id: lead.id,
                name: lead.name,
                email: lead.email,
                company: lead.company,
                isCompanyAdmin,
                isCoAdmin: lead.is_co_admin || false,
                clientPortalId,
                planKey:    planData.planKey,
                planLimits: planData,
            }
        });

    } catch (error) {
        console.error('[CLIENT LOGIN ERROR]', error);
        res.status(500).json({ success: false, message: 'Server error during login. Please try again.' });
    }
});


// POST /api/client/company/promote-admin - Promote user to co-admin
app.post('/api/client/company/promote-admin', authenticateClient, async (req, res) => {
    try {
        const { userId } = req.body; // company_users.id
        const email = req.user.email;
        
        // Verify requester is admin or co-admin
        const adminCheck = await pool.query(
            `SELECT client_portal_id, is_company_admin, is_co_admin 
             FROM leads WHERE email = $1`,
            [email]
        );
        
        if (!adminCheck.rows[0]?.is_company_admin && !adminCheck.rows[0]?.is_co_admin) {
            return res.status(403).json({ 
                success: false, 
                message: 'Only admins can promote users' 
            });
        }
        
        const clientPortalId = adminCheck.rows[0].client_portal_id;
        
        // Get user to promote
        const userResult = await pool.query(
            `SELECT * FROM company_users WHERE id = $1 AND client_portal_id = $2`,
            [userId, clientPortalId]
        );
        
        if (userResult.rows.length === 0) {
            return res.status(404).json({ success: false, message: 'User not found' });
        }
        
        const user = userResult.rows[0];
        
        // Update company_users
        await pool.query(
            `UPDATE company_users SET is_admin = TRUE WHERE id = $1`,
            [userId]
        );
        
        // Update/create lead record as co-admin
        await pool.query(`
            UPDATE leads 
            SET is_co_admin = TRUE,
                client_portal_id = $1,
                is_customer = TRUE,
                customer_status = 'active'
            WHERE email = $2
        `, [clientPortalId, user.user_email]);
        
        console.log(`[CO-ADMIN] Promoted ${user.user_email} to co-admin`);
        
        res.json({ 
            success: true, 
            message: `${user.user_name} promoted to co-admin` 
        });
    } catch (error) {
        console.error('[CO-ADMIN] Promotion error:', error);
        res.status(500).json({ success: false, message: 'Server error' });
    }
});

// POST /api/client/company/demote-admin - Remove co-admin status
app.post('/api/client/company/demote-admin', authenticateClient, async (req, res) => {
    try {
        const { userId } = req.body;
        const email = req.user.email;
        
        // Verify requester is company admin (not co-admin)
        const adminCheck = await pool.query(
            `SELECT client_portal_id, is_company_admin FROM leads WHERE email = $1`,
            [email]
        );
        
        if (!adminCheck.rows[0]?.is_company_admin) {
            return res.status(403).json({ 
                success: false, 
                message: 'Only company admins can demote co-admins' 
            });
        }
        
        const clientPortalId = adminCheck.rows[0].client_portal_id;
        
        // Get user
        const userResult = await pool.query(
            `SELECT * FROM company_users WHERE id = $1 AND client_portal_id = $2`,
            [userId, clientPortalId]
        );
        
        if (userResult.rows.length === 0) {
            return res.status(404).json({ success: false, message: 'User not found' });
        }
        
        const user = userResult.rows[0];
        
        // Update tables
        await pool.query(
            `UPDATE company_users SET is_admin = FALSE WHERE id = $1`,
            [userId]
        );
        
        await pool.query(
            `UPDATE leads SET is_co_admin = FALSE WHERE email = $1`,
            [user.user_email]
        );
        
        console.log(`[CO-ADMIN] Demoted ${user.user_email}`);
        
        res.json({ success: true, message: `${user.user_name} removed from co-admin` });
    } catch (error) {
        console.error('[CO-ADMIN] Demotion error:', error);
        res.status(500).json({ success: false, message: 'Server error' });
    }
});

// ==================== AUTHENTICATION MIDDLEWARE ====================

function authenticateClient(req, res, next) {
    const authHeader = req.headers.authorization;
    const token = authHeader && authHeader.split(' ')[1];
    
    if (!token) {
        console.log('[AUTH] No token provided');
        return res.status(401).json({ 
            success: false, 
            message: 'Access denied. Please log in.' 
        });
    }
    
    try {
        const decoded = jwt.verify(token, JWT_SECRET);
        
        if (decoded.type !== 'client') {
            console.log('[AUTH] Invalid token type:', decoded.type);
            return res.status(403).json({ 
                success: false, 
                message: 'Invalid access token.' 
            });
        }
        
        req.user = decoded;
        console.log('[AUTH] Client authenticated:', decoded.email);
        next();
        
    } catch (error) {
        console.error('[AUTH] Token verification failed:', error.message);
        return res.status(401).json({ 
            success: false, 
            message: 'Session expired. Please log in again.' 
        });
    }
}

// Mark a lead as contacted (updates last_contact_date)
// ========================================
// LEAD TEMPERATURE & ENGAGEMENT TRACKING
// ========================================

// Function to calculate next follow-up date based on temperature
function calculateNextFollowUpDate(lastContactDate, leadTemperature) {
    if (!lastContactDate) {
        return new Date(); // If never contacted, follow up immediately
    }
    
    const last = new Date(lastContactDate);
    const daysSinceContact = Math.floor((new Date() - last) / (1000 * 60 * 60 * 24));
    
    if (leadTemperature === 'hot') {
        // Hot leads: Fixed 3.5 day intervals (twice per week)
        return new Date(last.getTime() + 3.5 * 24 * 60 * 60 * 1000);
    } else {
        // Cold leads: Days 0, 3, 7, then weekly
        if (daysSinceContact === 0) return new Date(last.getTime() + 3 * 24 * 60 * 60 * 1000); // Day 3
        if (daysSinceContact === 3) return new Date(last.getTime() + 7 * 24 * 60 * 60 * 1000); // Day 7
        // After day 7: weekly
        return new Date(last.getTime() + 7 * 24 * 60 * 60 * 1000);
    }
}

// Function to add engagement event to lead
async function trackEngagement(leadId, engagementType, details = '') {
    try {
        console.log(`\n========================================`);
        console.log(`[ENGAGEMENT]  TRACKING ENGAGEMENT`);
        console.log(`[ENGAGEMENT] Lead ID: ${leadId}`);
        console.log(`[ENGAGEMENT] Type: ${engagementType}`);
        console.log(`[ENGAGEMENT] Details: ${details}`);
        console.log(`========================================\n`);
        
        const engagementEvent = {
            type: engagementType, // 'form_fill', 'email_click', 'email_reply', 'website_visit'
            details: details,
            timestamp: new Date().toISOString()
        };
        
        // Get current engagement history
        const leadResult = await pool.query(
            'SELECT id, name, email, engagement_history, engagement_score, lead_temperature, follow_up_count, last_contact_date FROM leads WHERE id = $1',
            [leadId]
        );
        
        if (leadResult.rows.length === 0) {
            console.log(`[ENGAGEMENT]  ERROR: Lead ${leadId} not found!`);
            return;
        }
        
        console.log(`[ENGAGEMENT]  CURRENT STATE:`, {
            name: leadResult.rows[0].name,
            email: leadResult.rows[0].email,
            temperature: leadResult.rows[0].lead_temperature,
            score: leadResult.rows[0].engagement_score,
            followUpCount: leadResult.rows[0].follow_up_count,
            lastContactDate: leadResult.rows[0].last_contact_date
        });
        
        const lead = leadResult.rows[0];
        let history = lead.engagement_history || [];
        let score = lead.engagement_score || 0;
        
        // Add new event to history
        history.push(engagementEvent);
        
        // Update engagement score based on type
        const scoreMap = {
            'form_fill': 30,              // Form fill = instant hot
            'email_click_hot': 30,         // Email link click = instant hot (NEW!)
            'website_visit_contact': 30,   // Contact page visit = instant hot
            'email_reply': 25,             // Email reply = instant hot
            'website_visit': 15,           // Regular website visit
            'email_click': 10,             // Clicked email link (old - not used anymore)
            'email_open': 5                // Opened email
        };
        score += scoreMap[engagementType] || 5;
        
        console.log(`[ENGAGEMENT]  NEW SCORE: ${score} (added ${scoreMap[engagementType] || 5} points for ${engagementType})`);
        
        // CRITICAL: Leads become hot through:
        // 1. Filling out a form (form_fill) → INSTANT HOT
        // 2. Clicking ANY link in an email (email_click_hot) → INSTANT HOT (NEW!)
        // 3. Visiting contact page (website_visit_contact) → INSTANT HOT
        // 4. Replying to an email (email_reply) → INSTANT HOT
        // 5. Accumulating 30+ engagement points naturally
        const shouldBeHot = lead.lead_temperature === 'hot' || 
                           score >= 30 || 
                           engagementType === 'form_fill' || 
                           engagementType === 'email_click_hot' ||
                           engagementType === 'email_reply' ||
                           engagementType === 'website_visit_contact';
        const newTemperature = shouldBeHot ? 'hot' : 'cold';
        
        console.log(`[ENGAGEMENT] ️  TEMPERATURE DECISION:`);
        console.log(`   - Current: ${lead.lead_temperature || 'null'}`);
        console.log(`   - New: ${newTemperature}`);
        console.log(`   - Should be hot? ${shouldBeHot}`);
        console.log(`   - Reasons: score >= 30? ${score >= 30}, form_fill? ${engagementType === 'form_fill'}, email_click? ${engagementType === 'email_click_hot'}, contact_page? ${engagementType === 'website_visit_contact'}, email_reply? ${engagementType === 'email_reply'}`);
        
        // If lead just became hot (cold -> hot transition)
        if (newTemperature === 'hot' && lead.lead_temperature !== 'hot') {
            console.log(`[ENGAGEMENT]  Lead ${leadId} became HOT! Cancelling auto-campaigns and RESETTING TIMELINE...`);
            
            // Cancel any active auto-campaigns for this lead
            await pool.query(
                `UPDATE auto_campaigns 
                 SET is_active = FALSE, 
                     stopped_at = CURRENT_TIMESTAMP,
                     stop_reason = 'Lead became hot - engagement detected'
                 WHERE lead_id = $1 AND is_active = TRUE`,
                [leadId]
            );
            
            // CRITICAL FIX: When ANY lead becomes hot, reset timeline so they show IMMEDIATELY
            // This includes email_open, email_click, form_fill, everything
            await pool.query(
                `UPDATE leads 
                 SET engagement_history = $1,
                     engagement_score = $2,
                     lead_temperature = $3,
                     became_hot_at = CURRENT_TIMESTAMP,
                     last_engagement_at = CURRENT_TIMESTAMP,
                     last_contact_date = NULL,
                     follow_up_count = 0
                 WHERE id = $4`,
                [JSON.stringify(history), score, newTemperature, leadId]
            );
            console.log(`[ENGAGEMENT]  Lead ${leadId} became HOT via ${engagementType} - TIMELINE RESET TO SHOW IMMEDIATELY IN QUEUE`);
        } else {
            // Normal update (not becoming hot)
            // For hot leads, only reset timeline if they've NEVER been contacted before
            // Once contacted, they stay in the normal hot lead follow-up cycle
            if (newTemperature === 'hot') {
                // Check if this hot lead has been contacted before
                if (lead.follow_up_count === 0 || lead.last_contact_date === null) {
                    // Never contacted - reset timeline to show them immediately
                    await pool.query(
                        `UPDATE leads 
                         SET engagement_history = $1,
                             engagement_score = $2,
                             lead_temperature = $3,
                             became_hot_at = COALESCE(became_hot_at, CURRENT_TIMESTAMP),
                             last_engagement_at = CURRENT_TIMESTAMP,
                             last_contact_date = NULL,
                             follow_up_count = 0
                         WHERE id = $4`,
                        [JSON.stringify(history), score, newTemperature, leadId]
                    );
                    console.log(`[ENGAGEMENT]  Hot lead ${leadId} engaged (never contacted) - showing in queue`);
                } else {
                    // Already contacted - DO NOT reset timeline
                    // Just update engagement data, keep their follow-up schedule intact
                    await pool.query(
                        `UPDATE leads 
                         SET engagement_history = $1,
                             engagement_score = $2,
                             lead_temperature = $3,
                             became_hot_at = COALESCE(became_hot_at, CURRENT_TIMESTAMP),
                             last_engagement_at = CURRENT_TIMESTAMP
                         WHERE id = $4`,
                        [JSON.stringify(history), score, newTemperature, leadId]
                    );
                    console.log(`[ENGAGEMENT]  Hot lead ${leadId} engaged (already contacted) - maintaining follow-up schedule`);
                }
            } else {
                // Cold lead - standard update
                await pool.query(
                    `UPDATE leads 
                     SET engagement_history = $1,
                         engagement_score = $2,
                         lead_temperature = $3,
                         last_engagement_at = CURRENT_TIMESTAMP
                     WHERE id = $4`,
                    [JSON.stringify(history), score, newTemperature, leadId]
                );
            }
        }
        
        console.log(`[ENGAGEMENT]  Tracked ${engagementType} for lead ${leadId}`);
        console.log(`[ENGAGEMENT]  FINAL STATE: Score: ${score} | Temp: ${newTemperature}`);
        console.log(`========================================\n`);
        
        return { success: true, temperature: newTemperature, score };
    } catch (error) {
        console.error('[ENGAGEMENT] Error tracking engagement:', error);
        return { success: false };
    }
}

