// Track email link clicks
app.get('/api/track/click/:leadId', async (req, res) => {
    try {
        const leadId = req.params.leadId;
        const { url, email_id } = req.query;
        
        console.log(`\n========================================`);
        console.log(`[TRACKING] ️  EMAIL LINK CLICKED!`);
        console.log(`[TRACKING] Lead ID: ${leadId}`);
        console.log(`[TRACKING] Email ID: ${email_id}`);
        console.log(`[TRACKING] URL: ${url}`);
        console.log(`========================================\n`);
        
        // Get email type and current status to determine if this should make the lead hot
        let emailType = null;
        let currentStatus = null;
        if (email_id) {
            try {
                const emailResult = await pool.query(
                    `SELECT email_type, status, opened_at FROM email_log WHERE id = $1`,
                    [email_id]
                );
                const emailData = emailResult.rows[0];
                emailType = emailData?.email_type;
                currentStatus = emailData?.status;
                console.log(`[TRACKING] Email type: ${emailType}, Current status: ${currentStatus}`);
                
                // CRITICAL: If someone clicked a link, the email MUST have been:
                // 1. Delivered (sent) - otherwise they couldn't receive it
                // 2. Opened - otherwise they couldn't see the link to click
                // So we update ALL three: status to 'sent', opened_at, and clicked_at
                await pool.query(
                    `UPDATE email_log 
                     SET clicked_at = COALESCE(clicked_at, CURRENT_TIMESTAMP),
                         opened_at = COALESCE(opened_at, CURRENT_TIMESTAMP),
                         status = CASE 
                            WHEN status IN ('pending', 'queued') THEN 'sent'
                            ELSE status
                         END
                     WHERE id = $1`,
                    [email_id]
                );
                console.log(`[TRACKING]  Updated email_log ${email_id}: status → sent, opened_at set, clicked_at set`);
                console.log(`[TRACKING] Logic: User clicked link → email MUST have been delivered and opened`);
            } catch (err) {
                console.error('[TRACKING] Error updating email_log:', err);
            }
        }
        
        // Follow-up AND marketing email clicks both immediately convert lead to hot
        if (emailType === 'follow-up' || emailType === 'marketing') {
            console.log(`[TRACKING]  ${(emailType||'').toUpperCase()} EMAIL LINK CLICKED - Making lead HOT immediately!`);
            const result = await trackEngagement(leadId, 'email_click_hot', `Clicked ${emailType} email link: ${url || 'unknown'}`);
            console.log(`[TRACKING]  Lead ${leadId} engagement result:`, result);
            if (result?.temperature === 'hot') {
                console.log(`[TRACKING]  LEAD ${leadId} IS NOW HOT `);
            } else {
                console.log(`[TRACKING] ️ WARNING: Lead did not become hot - check trackEngagement function`);
            }
        } else {
            // All other email types (invoice, subscription, appointment) — track click but don't force hot
            console.log(`[TRACKING] ℹ️  Email type '${emailType}' click tracked (no hot conversion for this type)`);
        }
        
        // Redirect to the actual URL
        const redirectUrl = url || BASE_URL;
        res.redirect(redirectUrl);
    } catch (error) {
        console.error('[TRACKING] Error tracking click:', error);
        res.redirect(BASE_URL);
    }
});

