app.post('/api/client/customers', authenticateClient, async (req, res) => {
    try {
        const userId = await resolveLeadId(req.user.id, req.user.email) || req.user.id;
        const portalId = await getClientPortalId(userId);
        const { name, email, phone, company, notes } = req.body;
        if (!name) return res.status(400).json({ success: false, message: 'Name required' });

        // Check if lead already exists
        if (email) {
            const existingQ = portalId
                ? `SELECT id FROM leads WHERE LOWER(email)=LOWER($1) AND client_portal_id=$2 AND client_password IS NULL`
                : `SELECT id FROM leads WHERE LOWER(email)=LOWER($1) AND individual_owner_id=$2 AND client_password IS NULL`;
            const existing = await pool.query(existingQ, [email, portalId || userId]);
            if (existing.rows.length) {
                await pool.query(
                    `UPDATE leads SET is_customer=TRUE, customer_status='active', status='closed', updated_at=NOW() WHERE id=$1`,
                    [existing.rows[0].id]
                );
                await pool.query(`UPDATE client_chain_queue SET is_active=FALSE WHERE lead_id=$1`, [existing.rows[0].id]).catch(()=>{});
                const updated = await pool.query(`SELECT * FROM leads WHERE id=$1`, [existing.rows[0].id]);
                return res.json({ success: true, customer: updated.rows[0] });
            }
        }

        let result;
        if (portalId) {
            result = await pool.query(`
                INSERT INTO leads (name, email, phone, company, notes, source, is_customer, customer_status,
                    status, lead_temperature, client_portal_id, created_at, updated_at)
                VALUES ($1,$2,$3,$4,$5,'crm-portal',TRUE,'active','closed','cold',$6,NOW(),NOW()) RETURNING *
            `, [name, email||null, phone||null, company||null, notes||null, portalId]);
        } else {
            result = await pool.query(`
                INSERT INTO leads (name, email, phone, company, notes, source, is_customer, customer_status,
                    status, lead_temperature, individual_owner_id, created_at, updated_at)
                VALUES ($1,$2,$3,$4,$5,'crm-portal',TRUE,'active','closed','cold',$6,NOW(),NOW()) RETURNING *
            `, [name, email||null, phone||null, company||null, notes||null, userId]);
        }
        res.json({ success: true, customer: result.rows[0] });
    } catch(e) { res.status(500).json({ success: false, message: e.message }); }
});

app.post('/api/client/leads/:id/convert', authenticateClient, async (req, res) => {
    try {
        const userId = await resolveLeadId(req.user.id, req.user.email);
        if (!userId) return res.status(400).json({ success: false, message: 'Account not found. Please log out and log back in.' });
        const portalId = await getClientPortalId(userId);
        const leadId = req.params.id;
        // Verify lead belongs to this account (portal or individual)
        const check = portalId
            ? await pool.query(`SELECT id FROM leads WHERE id=$1 AND client_portal_id=$2 AND client_password IS NULL`, [leadId, portalId])
            : await pool.query(`SELECT id FROM leads WHERE id=$1 AND individual_owner_id=$2 AND client_password IS NULL`, [leadId, userId]);
        if (!check.rows.length) return res.status(404).json({ success: false, message: 'Lead not found' });
        // Convert to customer
        await pool.query(`
            UPDATE leads SET
                is_customer=TRUE, customer_status='active',
                status='closed', updated_at=NOW()
            WHERE id=$1
        `, [leadId]);
        // Remove from all active follow-up chains
        await pool.query(`UPDATE client_chain_queue SET is_active=FALSE WHERE lead_id=$1`, [leadId]);
        const result = await pool.query(`SELECT * FROM leads WHERE id=$1`, [leadId]);
        res.json({ success: true, customer: result.rows[0] });
    } catch(e) { res.status(500).json({ success: false, message: e.message }); }
});

app.get('/api/client/charts', authenticateClient, async (req, res) => {
    try {
        const userId = await resolveLeadId(req.user.id, req.user.email) || req.user.id;
        const portalId = await getClientPortalId(userId);
        // Support both workspace (portalId) and individual users
        const isIndividual = !portalId;

        // Build array of last 12 months (YYYY-MM strings, oldest first)
        const months = [];
        const now = new Date();
        for (let i = 11; i >= 0; i--) {
            const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
            months.push(`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`);
        }
        const oldest = months[0] + '-01';

        // ── Income data: sum of product prices per lead per month
        //    "potential" = leads (not yet customers) with products
        //    "actual"    = customers with products
        const incomeRows = isIndividual
            ? await pool.query(`
                SELECT TO_CHAR(l.created_at,'YYYY-MM') as month,
                    CASE WHEN l.is_customer=TRUE THEN 'actual' ELSE 'potential' END as income_type,
                    COALESCE(SUM(p.price),0) as total
                FROM leads l
                JOIN lead_products lp ON lp.lead_id=l.id
                JOIN client_products p ON p.id=lp.product_id
                WHERE l.individual_owner_id=$1 AND l.client_password IS NULL AND l.created_at>=$2::date
                GROUP BY month,income_type ORDER BY month ASC`, [userId, oldest])
            : await pool.query(`
                SELECT TO_CHAR(l.created_at,'YYYY-MM') as month,
                    CASE WHEN l.is_customer=TRUE THEN 'actual' ELSE 'potential' END as income_type,
                    COALESCE(SUM(p.price),0) as total
                FROM leads l
                JOIN lead_products lp ON lp.lead_id=l.id
                JOIN client_products p ON p.id=lp.product_id
                WHERE l.client_portal_id=$1 AND l.client_password IS NULL AND l.created_at>=$2::date
                GROUP BY month,income_type ORDER BY month ASC`, [portalId, oldest]);

        // ── Growth data: leads added per month and customers converted per month
        const growthRows = isIndividual
            ? await pool.query(`
                SELECT TO_CHAR(created_at,'YYYY-MM') as month,
                    COUNT(*) FILTER (WHERE is_customer IS NOT TRUE) as leads, 0 as customers
                FROM leads WHERE individual_owner_id=$1 AND client_password IS NULL
                  AND (source IS NULL OR source NOT IN ('company-user','subscription-direct'))
                  AND created_at>=$2::date GROUP BY month
                UNION ALL
                SELECT TO_CHAR(updated_at,'YYYY-MM') as month, 0 as leads, COUNT(*) as customers
                FROM leads WHERE individual_owner_id=$1 AND client_password IS NULL AND is_customer=TRUE
                  AND updated_at>=$2::date
                  AND (source IS NULL OR source NOT IN ('company-user','subscription-direct'))
                GROUP BY month ORDER BY month ASC`, [userId, oldest])
            : await pool.query(`
                SELECT TO_CHAR(created_at,'YYYY-MM') as month,
                    COUNT(*) FILTER (WHERE is_customer IS NOT TRUE) as leads, 0 as customers
                FROM leads WHERE client_portal_id=$1 AND client_password IS NULL
                  AND (source IS NULL OR source NOT IN ('company-user','subscription-direct'))
                  AND created_at>=$2::date GROUP BY month
                UNION ALL
                SELECT TO_CHAR(updated_at,'YYYY-MM') as month, 0 as leads, COUNT(*) as customers
                FROM leads WHERE client_portal_id=$1 AND client_password IS NULL AND is_customer=TRUE
                  AND updated_at>=$2::date
                  AND (source IS NULL OR source NOT IN ('company-user','subscription-direct'))
                GROUP BY month ORDER BY month ASC`, [portalId, oldest]);

        // ── Product popularity: how many leads assigned each product per month
        const productRows = isIndividual
            ? await pool.query(`
                SELECT TO_CHAR(l.created_at,'YYYY-MM') as month, p.id as product_id, p.name as product_name, COUNT(*) as count
                FROM leads l JOIN lead_products lp ON lp.lead_id=l.id JOIN client_products p ON p.id=lp.product_id
                WHERE l.individual_owner_id=$1 AND l.client_password IS NULL AND l.created_at>=$2::date
                GROUP BY month,p.id,p.name ORDER BY month ASC,p.name ASC`, [userId, oldest])
            : await pool.query(`
                SELECT TO_CHAR(l.created_at,'YYYY-MM') as month, p.id as product_id, p.name as product_name, COUNT(*) as count
                FROM leads l JOIN lead_products lp ON lp.lead_id=l.id JOIN client_products p ON p.id=lp.product_id
                WHERE l.client_portal_id=$1 AND l.client_password IS NULL AND l.created_at>=$2::date
                GROUP BY month,p.id,p.name ORDER BY month ASC,p.name ASC`, [portalId, oldest]);

        // ── Current month vs previous month actual income
        const curMonth = months[11]; // most recent
        const prevMonth = months[10];

        const incomeMap = {};
        for (const r of incomeRows.rows) {
            if (!incomeMap[r.month]) incomeMap[r.month] = { potential: 0, actual: 0 };
            incomeMap[r.month][r.income_type] = parseFloat(r.total) || 0;
        }
        const curActual  = incomeMap[curMonth]?.actual  || 0;
        const prevActual = incomeMap[prevMonth]?.actual || 0;
        const pctChange  = prevActual === 0
            ? (curActual > 0 ? 100 : 0)
            : Math.round(((curActual - prevActual) / prevActual) * 100 * 10) / 10;

        // ── Shape income data into month-keyed array
        const income = months.map(m => ({
            month: m,
            potential: incomeMap[m]?.potential || 0,
            actual:    incomeMap[m]?.actual    || 0,
        }));

        // ── Shape growth data (UNION ALL may produce multiple rows per month — aggregate)
        const growthMap = {};
        for (const r of growthRows.rows) {
            if (!growthMap[r.month]) growthMap[r.month] = { leads: 0, customers: 0 };
            growthMap[r.month].leads     += parseInt(r.leads)||0;
            growthMap[r.month].customers += parseInt(r.customers)||0;
        }
        const growth = months.map(m => ({ month: m, leads: growthMap[m]?.leads||0, customers: growthMap[m]?.customers||0 }));

        // ── Shape product data
        const products = productRows.rows.map(r => ({
            month: r.month, product_id: r.product_id, product_name: r.product_name, count: parseInt(r.count)||0
        }));

        res.json({
            success: true,
            months,
            income,
            growth,
            products,
            currentMonthIncome: { actual: curActual, prevActual, pctChange }
        });
    } catch(e) {
        console.error('[CHARTS]', e);
        res.status(500).json({ success: false, message: e.message });
    }
});

