// POST /api/client/bg-images — upload a new bg image (admin or individual account owner)
app.post('/api/client/bg-images', authenticateClient, bgImageUpload.single('image'), async (req, res) => {
    try {
        if (!req.file) return res.status(400).json({ success: false, message: 'No file uploaded' });

        // Resolve real lead id in case JWT id is stale
        const resolvedUserId = await resolveLeadId(req.user.id, req.user.email) || req.user.id;

        let portalId = await getClientPortalId(resolvedUserId);
        let isIndividualBg = false;

        if (!portalId) {
            // Individual user — they own their account, allow upload using their lead ID as scope
            const leadRow = await pool.query(
                `SELECT id, email FROM leads WHERE id=$1`, [resolvedUserId]
            );
            if (!leadRow.rows[0]) {
                require('fs').unlink(req.file.path, () => {});
                return res.status(400).json({ success: false, message: 'User not found' });
            }
            isIndividualBg = true;
        } else {
            // Workspace/company — admin only
            const adminCheck = await pool.query(
                `SELECT is_company_admin, is_co_admin FROM leads WHERE id=$1`, [resolvedUserId]
            );
            const u = adminCheck.rows[0];
            let isAdminBg = u?.is_company_admin || u?.is_co_admin;
            if (!isAdminBg) {
                const cuAdmin = await pool.query(
                    `SELECT is_admin FROM company_users WHERE client_portal_id=$1 AND LOWER(user_email)=LOWER($2) AND status='active' LIMIT 1`,
                    [portalId, req.user.email]
                ).catch(() => ({ rows: [] }));
                isAdminBg = cuAdmin.rows[0]?.is_admin || false;
            }
            if (!isAdminBg) {
                require('fs').unlink(req.file.path, () => {});
                return res.status(403).json({ success: false, message: 'Admin only' });
            }
        }

        // Limit to 10 custom backgrounds per account
        const countRes = isIndividualBg
            ? await pool.query(`SELECT COUNT(*) FROM portal_bg_images WHERE lead_id=$1`, [resolvedUserId])
            : await pool.query(`SELECT COUNT(*) FROM portal_bg_images WHERE client_portal_id=$1`, [portalId]);
        if (parseInt(countRes.rows[0].count) >= 10) {
            require('fs').unlink(req.file.path, () => {});
            return res.status(400).json({ success: false, message: 'Maximum 10 custom backgrounds per account. Delete one first.' });
        }

        const url = '/uploads/bg-images/' + req.file.filename;
        const label = req.body.label?.trim().slice(0, 40) || 'Custom';

        // Insert — individual uses lead_id column, workspace uses client_portal_id
        const row = isIndividualBg
            ? await pool.query(
                `INSERT INTO portal_bg_images (lead_id, url, label, uploaded_by)
                 VALUES ($1,$2,$3,$4) RETURNING id, url, label, uploaded_by, created_at`,
                [resolvedUserId, url, label, req.user.email]
              )
            : await pool.query(
                `INSERT INTO portal_bg_images (client_portal_id, url, label, uploaded_by)
                 VALUES ($1,$2,$3,$4) RETURNING id, url, label, uploaded_by, created_at`,
                [portalId, url, label, req.user.email]
              );
        res.json({ success: true, image: row.rows[0] });
    } catch(e) {
        console.error('[BG IMAGE UPLOAD]', e);
        res.status(500).json({ success: false, message: e.message });
    }
});

// DELETE /api/client/bg-images/:id — delete a custom bg image (admin or individual owner)
app.delete('/api/client/bg-images/:id', authenticateClient, async (req, res) => {
    try {
        const portalId = await getClientPortalId(req.user.id);
        let isIndividualDel = false;

        if (!portalId) {
            // Individual user — owns all their own bg images
            isIndividualDel = true;
        } else {
            // Workspace/company — admin only
            const adminCheck = await pool.query(
                `SELECT is_company_admin, is_co_admin FROM leads WHERE id=$1`, [req.user.id]
            );
            const u = adminCheck.rows[0];
            let isAdminDel = u?.is_company_admin || u?.is_co_admin;
            if (!isAdminDel) {
                const cuAdmin = await pool.query(
                    `SELECT is_admin FROM company_users WHERE client_portal_id=$1 AND LOWER(user_email)=LOWER($2) AND status='active' LIMIT 1`,
                    [portalId, req.user.email]
                ).catch(() => ({ rows: [] }));
                isAdminDel = cuAdmin.rows[0]?.is_admin || false;
            }
            if (!isAdminDel) return res.status(403).json({ success: false, message: 'Admin only' });
        }

        const imgRes = isIndividualDel
            ? await pool.query(
                `DELETE FROM portal_bg_images WHERE id=$1 AND lead_id=$2 RETURNING url`,
                [req.params.id, req.user.id]
              )
            : await pool.query(
                `DELETE FROM portal_bg_images WHERE id=$1 AND client_portal_id=$2 RETURNING url`,
                [req.params.id, portalId]
              );
        if (!imgRes.rows[0]) return res.status(404).json({ success: false, message: 'Image not found' });

        const filePath = require('path').join(__dirname, imgRes.rows[0].url);
        require('fs').unlink(filePath, () => {});

        res.json({ success: true });
    } catch(e) { res.status(500).json({ success: false, message: e.message }); }
});



// ============================================================
// INTEGRATIONS — Full suite
// All routes require Enterprise or Workspace plan
// ============================================================

// Helper: resolve integration scope (lead_id for individual, portal_id for workspace)
async function getIntegrationScope(userId) {
    const portalId = await getClientPortalId(userId);
    return { portalId: portalId || null, leadId: portalId ? null : userId };
}

// Helper: check integrations are enabled on this plan
async function requireIntegrations(req, res) {
    // Try multiple ID resolution strategies to avoid false denials for enterprise users
    const originalId = req.user.id;
    const resolvedId = await resolveLeadId(originalId, req.user.email).catch(() => originalId) || originalId;

    // Try resolved ID first, then fall back to original ID if resolved gives default plan
    let plan = await getClientPlanLimits(resolvedId);
    if ((plan.planKey === '_default' || !plan.integrationsEnabled) && resolvedId !== originalId) {
        const planByOriginal = await getClientPlanLimits(originalId);
        if (planByOriginal.planKey !== '_default') plan = planByOriginal;
    }

    // Check the flag first; also allow by planKey directly in case the flag is missing
    // from a legacy or fallback plan object (defensive double-check)
    const key = plan.planKey || '';
    const allowed = !!(plan.integrationsEnabled)
        || key === 'crm-enterprise'
        || key === 'crm-workspace'
        || key.includes('enterprise')
        || key.includes('workspace');
    if (!allowed) {
        res.status(403).json({ success: false, message: 'Integrations are available on Enterprise and Workspace plans.' });
        return false;
    }
    return true;
}

// Helper: fetch a stored integration
async function getIntegration(userId, key) {
    const { portalId, leadId } = await getIntegrationScope(userId);
    const r = portalId
        ? await pool.query(`SELECT * FROM crm_integrations WHERE client_portal_id=$1 AND integration_key=$2 AND status='active'`, [portalId, key])
        : await pool.query(`SELECT * FROM crm_integrations WHERE lead_id=$1 AND integration_key=$2 AND status='active'`, [leadId, key]);
    return r.rows[0] || null;
}

// Helper: save/update an integration
async function upsertIntegration(userId, key, data) {
    const { portalId, leadId } = await getIntegrationScope(userId);
    if (portalId) {
        await pool.query(`
            INSERT INTO crm_integrations (client_portal_id, integration_key, access_token, refresh_token, token_expires_at, account_id, account_name, account_email, metadata, connected_at, status)
            VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9,NOW(),'active')
            ON CONFLICT (client_portal_id, integration_key) DO UPDATE SET
                access_token=$3, refresh_token=$4, token_expires_at=$5, account_id=$6,
                account_name=$7, account_email=$8, metadata=$9, connected_at=NOW(), status='active'
        `, [portalId, key, data.accessToken||null, data.refreshToken||null, data.expiresAt||null,
            data.accountId||null, data.accountName||null, data.accountEmail||null, JSON.stringify(data.metadata||{})]);
    } else {
        await pool.query(`
            INSERT INTO crm_integrations (lead_id, integration_key, access_token, refresh_token, token_expires_at, account_id, account_name, account_email, metadata, connected_at, status)
            VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9,NOW(),'active')
            ON CONFLICT (lead_id, integration_key) DO UPDATE SET
                access_token=$3, refresh_token=$4, token_expires_at=$5, account_id=$6,
                account_name=$7, account_email=$8, metadata=$9, connected_at=NOW(), status='active'
        `, [leadId, key, data.accessToken||null, data.refreshToken||null, data.expiresAt||null,
            data.accountId||null, data.accountName||null, data.accountEmail||null, JSON.stringify(data.metadata||{})]);
    }
}

// Helper: disconnect an integration
async function removeIntegration(userId, key) {
    const { portalId, leadId } = await getIntegrationScope(userId);
    if (portalId) {
        await pool.query(`UPDATE crm_integrations SET status='disconnected' WHERE client_portal_id=$1 AND integration_key=$2`, [portalId, key]);
    } else {
        await pool.query(`UPDATE crm_integrations SET status='disconnected' WHERE lead_id=$1 AND integration_key=$2`, [leadId, key]);
    }
}

// ── GET /api/integrations/status — list all connected integrations for this user ──
app.get('/api/integrations/status', authenticateClient, async (req, res) => {
    try {
        if (!await requireIntegrations(req, res)) return;
        const { portalId, leadId } = await getIntegrationScope(req.user.id);
        const r = portalId
            ? await pool.query(`SELECT integration_key, account_name, account_email, connected_at, last_synced_at, status FROM crm_integrations WHERE client_portal_id=$1`, [portalId])
            : await pool.query(`SELECT integration_key, account_name, account_email, connected_at, last_synced_at, status FROM crm_integrations WHERE lead_id=$1`, [leadId]);
        const connected = {};
        r.rows.forEach(row => { connected[row.integration_key] = row; });
        res.json({ success: true, connected });
    } catch(e) { res.status(500).json({ success: false, message: e.message }); }
});

// ── DISCONNECT any integration ─────────────────────────────────────────────────
app.delete('/api/integrations/:key', authenticateClient, async (req, res) => {
    try {
        if (!await requireIntegrations(req, res)) return;
        await removeIntegration(req.user.id, req.params.key);
        res.json({ success: true });
    } catch(e) { res.status(500).json({ success: false, message: e.message }); }
});

