// ── Schema init ───────────────────────────────────────────────────
(async () => {
    try {
        await pool.query(`
            CREATE TABLE IF NOT EXISTS client_email_settings (
                id SERIAL PRIMARY KEY,
                client_portal_id VARCHAR(20) NOT NULL UNIQUE,
                brevo_api_key TEXT,
                sender_email VARCHAR(255),
                sender_name VARCHAR(255),
                company_name VARCHAR(255),
                company_phone VARCHAR(50),
                company_email VARCHAR(255),
                company_address TEXT,
                website_url VARCHAR(500),
                accent_color VARCHAR(20) DEFAULT '#FF6B35',
                created_at TIMESTAMP DEFAULT NOW(),
                updated_at TIMESTAMP DEFAULT NOW()
            );

            -- Migrate existing individual template support (safe if already done)
            DO $migtempl$ BEGIN
                IF NOT EXISTS (
                    SELECT 1 FROM information_schema.columns
                    WHERE table_name='client_email_templates' AND column_name='individual_owner_id'
                ) THEN
                    ALTER TABLE client_email_templates ADD COLUMN individual_owner_id INTEGER REFERENCES leads(id) ON DELETE CASCADE;
                END IF;
                -- Make client_portal_id nullable for individual users
                BEGIN
                    ALTER TABLE client_email_templates ALTER COLUMN client_portal_id DROP NOT NULL;
                EXCEPTION WHEN others THEN NULL;
                END;
            END $migtempl$;

            CREATE TABLE IF NOT EXISTS client_email_templates (
                id SERIAL PRIMARY KEY,
                client_portal_id VARCHAR(20),
                individual_owner_id INTEGER REFERENCES leads(id) ON DELETE CASCADE,
                name VARCHAR(255) NOT NULL,
                topic VARCHAR(100),
                eyebrow VARCHAR(255),
                headline VARCHAR(500),
                body_html TEXT NOT NULL,
                cta_label VARCHAR(100),
                subject VARCHAR(500) NOT NULL,
                is_automated BOOLEAN DEFAULT FALSE,
                created_by_user_email VARCHAR(255),
                website_url VARCHAR(500),
                website_btn_label VARCHAR(100),
                include_contact_form BOOLEAN DEFAULT TRUE,
                contact_btn_label VARCHAR(100),
                include_schedule_btn BOOLEAN DEFAULT TRUE,
                schedule_btn_label VARCHAR(100),
                created_at TIMESTAMP DEFAULT NOW(),
                updated_at TIMESTAMP DEFAULT NOW()
            );

            CREATE TABLE IF NOT EXISTS client_email_chains (
                id SERIAL PRIMARY KEY,
                client_portal_id VARCHAR(20) NOT NULL,
                name VARCHAR(255) NOT NULL,
                is_active BOOLEAN DEFAULT TRUE,
                loop BOOLEAN DEFAULT TRUE,
                created_at TIMESTAMP DEFAULT NOW()
            );

            CREATE TABLE IF NOT EXISTS client_email_chain_steps (
                id SERIAL PRIMARY KEY,
                chain_id INTEGER REFERENCES client_email_chains(id) ON DELETE CASCADE,
                template_id INTEGER REFERENCES client_email_templates(id) ON DELETE CASCADE,
                step_order INTEGER NOT NULL,
                delay_days INTEGER NOT NULL DEFAULT 3
            );

            CREATE TABLE IF NOT EXISTS client_email_log (
                id SERIAL PRIMARY KEY,
                client_portal_id VARCHAR(20),
                lead_id INTEGER REFERENCES leads(id) ON DELETE SET NULL,
                lead_email VARCHAR(255),
                assigned_to_user_email VARCHAR(255),
                template_id INTEGER,
                chain_id INTEGER,
                subject VARCHAR(500),
                email_type VARCHAR(100) DEFAULT 'marketing',
                status VARCHAR(50) DEFAULT 'pending',
                brevo_message_id VARCHAR(255),
                sent_at TIMESTAMP,
                opened_at TIMESTAMP,
                clicked_at TIMESTAMP,
                lead_became_hot BOOLEAN DEFAULT FALSE,
                to_email VARCHAR(255),
                error_message TEXT,
                created_at TIMESTAMP DEFAULT NOW()
            );

            CREATE TABLE IF NOT EXISTS client_unsubscribes (
                id SERIAL PRIMARY KEY,
                client_portal_id VARCHAR(20),
                email VARCHAR(255) NOT NULL,
                unsubscribed_at TIMESTAMP DEFAULT NOW(),
                UNIQUE(client_portal_id, email)
            );

            CREATE TABLE IF NOT EXISTS portal_bg_images (
                id SERIAL PRIMARY KEY,
                client_portal_id VARCHAR(20) NOT NULL,
                url TEXT NOT NULL,
                label VARCHAR(100),
                uploaded_by VARCHAR(255),
                created_at TIMESTAMP DEFAULT NOW()
            );

            CREATE TABLE IF NOT EXISTS client_chain_queue (
                id SERIAL PRIMARY KEY,
                client_portal_id VARCHAR(20),
                chain_id INTEGER REFERENCES client_email_chains(id) ON DELETE CASCADE,
                lead_id INTEGER REFERENCES leads(id) ON DELETE CASCADE,
                lead_email VARCHAR(255),
                current_step INTEGER DEFAULT 0,
                next_send_at TIMESTAMP,
                is_active BOOLEAN DEFAULT TRUE,
                created_at TIMESTAMP DEFAULT NOW(),
                UNIQUE(chain_id, lead_email)
            );
        `);

        // Indexes
        await pool.query(`
            CREATE INDEX IF NOT EXISTS idx_cel_portal ON client_email_log(client_portal_id);
            CREATE INDEX IF NOT EXISTS idx_cel_lead ON client_email_log(lead_id);
            CREATE INDEX IF NOT EXISTS idx_cel_brevo ON client_email_log(brevo_message_id) WHERE brevo_message_id IS NOT NULL;
            CREATE INDEX IF NOT EXISTS idx_cet_portal ON client_email_templates(client_portal_id);
            CREATE INDEX IF NOT EXISTS idx_ccq_next ON client_chain_queue(next_send_at) WHERE is_active = TRUE;
        `);

        // Migrate existing installs: add new template columns if missing
        const templateMigrations = [
            `ALTER TABLE client_email_templates ADD COLUMN IF NOT EXISTS website_url VARCHAR(500)`,
            `ALTER TABLE client_email_templates ADD COLUMN IF NOT EXISTS website_btn_label VARCHAR(100)`,
            `ALTER TABLE client_email_templates ADD COLUMN IF NOT EXISTS include_contact_form BOOLEAN DEFAULT TRUE`,
            `ALTER TABLE client_email_templates ADD COLUMN IF NOT EXISTS contact_btn_label VARCHAR(100)`,
            `ALTER TABLE client_email_templates ADD COLUMN IF NOT EXISTS include_schedule_btn BOOLEAN DEFAULT TRUE`,
            `ALTER TABLE client_email_templates ADD COLUMN IF NOT EXISTS schedule_btn_label VARCHAR(100)`,
        ];
        for (const sql of templateMigrations) {
            await pool.query(sql).catch(() => {});
        }
    } catch(e) {
        console.error('[CLIENT EMAIL] Schema init error:', e.message);
    }
})();

// ── Helper: get portal email settings ────────────────────────────
async function getClientEmailSettings(clientPortalId) {
    const r = await pool.query(
        'SELECT * FROM client_email_settings WHERE client_portal_id = $1',
        [clientPortalId]
    );
    return r.rows[0] || null;
}

// ── Helper: get clientPortalId for a user ────────────────────────
async function getClientPortalId(userId) {
    const r = await pool.query(
        'SELECT client_portal_id, email, is_company_admin FROM leads WHERE id = $1', [userId]
    );
    const row = r.rows[0];
    if (!row) return null;
    // Direct hit — most common case
    if (row.client_portal_id) return row.client_portal_id;
    // Admin whose portal ID wasn't stamped onto the lead record — look up from client_companies
    if (row.is_company_admin && row.email) {
        const cc = await pool.query(
            'SELECT client_portal_id FROM client_companies WHERE LOWER(admin_email) = LOWER($1) LIMIT 1',
            [row.email]
        );
        const portalId = cc.rows[0]?.client_portal_id || null;
        // Stamp it back onto the lead so we don't have to look it up again
        if (portalId) {
            await pool.query(
                'UPDATE leads SET client_portal_id = $1 WHERE id = $2',
                [portalId, userId]
            ).catch(() => {});
        }
        return portalId;
    }
    // Fallback for regular team members whose client_portal_id wasn't stamped on their lead row
    if (row.email) {
        const cu = await pool.query(
            `SELECT client_portal_id FROM company_users
             WHERE LOWER(user_email) = LOWER($1) AND status = 'active'
             LIMIT 1`,
            [row.email]
        );
        const portalId = cu.rows[0]?.client_portal_id || null;
        if (portalId) {
            await pool.query(
                'UPDATE leads SET client_portal_id = $1 WHERE id = $2',
                [portalId, userId]
            ).catch(() => {});
        }
        return portalId;
    }
    return null;
}

