// ── Helper: send via client's own Brevo key, or fall back to EmailJS ─
// senderUserEmail = the authenticated user making the request — this
// becomes the "From" address so every email comes from the actual person.
async function sendClientEmail({ portalId, leadId, leadEmail, senderUserEmail, assignedToUserEmail, templateId, chainId, subject, html, emailType = 'marketing' }) {
    const settings = await getClientEmailSettings(portalId);

    // ── Per-portal rate limit & suspension check ─────────────────
    const rateCheck = await checkPortalRateLimit(portalId);
    if (!rateCheck.allowed) {
        throw new Error(rateCheck.reason);
    }

    // ── Determine FROM address ────────────────────────────────────
    // Priority order:
    //   1. User's own email (always used as fromEmail when they are the sender)
    //      with their per-user sender_name from company_users (set by admin)
    //   2. Portal-wide sender_email / sender_name from client_email_settings
    //   3. company_email / company_name as last resort
    let fromEmail = null;
    let fromName  = null;

    if (senderUserEmail) {
        // For individual users (portalId=null), skip the company_users lookup entirely —
        // PostgreSQL's "= NULL" never matches, so we just use the email directly.
        if (portalId) {
            // Look up the sending user's record — use their email + admin-assigned sender_name
            const userRow = await pool.query(
                `SELECT user_name, sender_name FROM company_users
                 WHERE LOWER(user_email) = LOWER($1) AND client_portal_id = $2 LIMIT 1`,
                [senderUserEmail, portalId]
            ).catch(() => ({ rows: [] }));
            const cu = userRow.rows[0];
            if (cu) {
                fromEmail = senderUserEmail.toLowerCase();
                // Use admin-assigned sender_name if set, otherwise fall back to user_name
                fromName = cu.sender_name || cu.user_name || senderUserEmail.split('@')[0];
            }
        } else {
            // Individual (no portal) — use their own email directly as the sender
            fromEmail = senderUserEmail.toLowerCase();
            fromName  = senderUserEmail.split('@')[0];
        }
    }

    // Fallback to portal-wide sender
    if (!fromEmail) {
        fromEmail = settings?.sender_email || settings?.company_email || null;
        fromName  = settings?.sender_name  || settings?.company_name  || fromEmail || 'CRM';
    }

    // Log the email first
    let logId = null;
    try {
        const logRow = await pool.query(`
            INSERT INTO client_email_log
                (client_portal_id, lead_id, lead_email, assigned_to_user_email,
                 template_id, chain_id, subject, email_type, status, created_at)
            VALUES ($1,$2,$3,$4,$5,$6,$7,$8,'pending',NOW())
            RETURNING id
        `, [portalId, leadId||null, leadEmail, assignedToUserEmail||senderUserEmail||null, templateId||null, chainId||null, subject, emailType]);
        logId = logRow.rows[0]?.id;
    } catch(e) { console.error('[CLIENT EMAIL] Log insert failed:', e.message); }

    // Inject open-tracking pixel
    const pixelUrl = `${BASE_URL}/api/client-track/open/${logId}`;
    html = html.replace('</body>', `<img src="${pixelUrl}" width="1" height="1" style="display:none;" alt=""/></body>`);

    // Wrap website links with click tracking (triggers hot conversion on click)
    if (settings?.website_url && logId && leadId) {
        const escapedUrl = settings.website_url.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const urlPattern = new RegExp(`(${escapedUrl}[^"'\\s]*)`, 'gi');
        html = html.replace(urlPattern, (match) => {
            if (match.includes('/api/client-track/')) return match;
            return `${BASE_URL}/api/client-track/click/${logId}?lead_id=${leadId}&portal_id=${portalId}&url=${encodeURIComponent(match)}`;
        });
    }

    // ── Use Diamondback's platform Brevo key — never per-portal keys ─
    const masterBrevoKey = PLATFORM_BREVO_KEY;
    if (!masterBrevoKey) {
        await pool.query(`UPDATE client_email_log SET status='failed', error_message='BREVO_API_KEY env var not set on server' WHERE id=$1`, [logId]);
        console.error('[CLIENT EMAIL] ❌ CRITICAL: BREVO_API_KEY environment variable is not set on Render!');
        throw new Error('Email service not configured. The BREVO_API_KEY environment variable must be set on your Render server. Go to Render → your service → Environment, and add BREVO_API_KEY with your Brevo API key.');
    }
    if (!fromEmail) {
        await pool.query(`UPDATE client_email_log SET status='failed', error_message='No sender email configured' WHERE id=$1`, [logId]);
        throw new Error('No sender email configured in portal settings.');
    }

    try {
        // Pass verified domain so sendViaBrevo can send directly from client address
        const verifiedDomain = (settings?.domain_status === 'verified') ? settings.verified_domain : null;
        const brevoResult = await sendViaBrevo(
            masterBrevoKey,
            fromEmail,
            fromName,
            leadEmail,
            subject,
            html,
            [],           // no attachments
            verifiedDomain
        );
        const msgId = brevoResult?.messageId || null;

        await pool.query(`
            UPDATE client_email_log
            SET status='sent', sent_at=NOW(), brevo_message_id=$2
            WHERE id=$1
        `, [logId, msgId || null]);

        // Increment daily send counter for deliverability tracking
        await incrementPortalEmailCount(portalId);

        // Record usage for billing at 2× Brevo rates
        await recordUsage({
            clientPortalId: portalId,
            eventType: 'email',
            leadId,
            leadEmail,
            subject,
            brevoMessageId: msgId
        });

        console.log(`[CLIENT EMAIL] ✅ Sent via platform Brevo from ${fromEmail} → ${leadEmail}`);
        return { success: true, logId, messageId: msgId, method: 'brevo' };
    } catch(brevoErr) {
        console.error('[CLIENT EMAIL] ❌ Platform Brevo send failed:', brevoErr.message);
        await pool.query(`UPDATE client_email_log SET status='failed', error_message=$2 WHERE id=$1`, [logId, brevoErr.message]);
        throw brevoErr;
    }
}

